mapper.select:
select af.af_id as id, af.tel_id as telId, gc.city_id as cityCode, gc.city_name as cityName, af.estimated_grade as aqiValue, concat(af.af_date, ' ', af.af_time) as feedbackTime, af.state as state, af.gm_id as gmId, gm.gm_name as gmName, concat(af.assign_date, ' ', af.assign_time) as assignTime, af.information as remark from aqi_feedback af left join grid_city gc on af.city_id = gc.city_id left join grid_member gm on af.gm_id = gm.gm_id
and af.state = #{queryVo.state}
and gc.city_id = #{queryVo.cityCode}
and af.tel_id like concat('%', #{queryVo.telId}, '%')
and concat(af.af_date, ' ', af.af_time) >= #{queryVo.startTime}
and concat(af.af_date, ' ', af.af_time) <= #{queryVo.endTime}
